 14→//RES_LOGN controls the resolution of cosine tables in transform functions.
 15→//It also decide the value of RES_N is (1 << RES_LOGN)
 16→#ifndef RES_LOGN
 17→#define RES_LOGN    (10)            //default is 10
 18→#endif
 19→
 20→//RES_N is decided by RES_LOGN and it should not be defined manully.
 21→#ifdef RES_N
 22→#undef RES_N
 23→#endif
 24→#define RES_N       (1 << RES_LOGN)
 25→
 26→
 27→//FFT_LOGN is idnetical with RES_LOGN in default configuration.
 28→//
 29→//If user wish to use lower resolution for larger samples transform,
 30→//i.e. the samples in a frame is lager then the coeffients in cosine table.
 31→//then FFT_LOGN should be set to RES_LOGN + 1
 32→//(any value greater than RES_LOGN is OK, since we only check if FFT_LOGN > RES_LOGN).
 33→//This leads lower precision but use smaller cosine table.
 34→#ifndef FFT_LOGN
 35→#define FFT_LOGN    RES_LOGN
 36→#endif
 37→
 38→//Only used by STATIC_VERSION
 39→#define FFT_N (1 << FFT_LOGN)
 40→
 41→//COS_RES_N controls the resolution of cosine tables in nds_cos_xx and nds_sin_xx functions.
 42→//The value of COS_RES_N is identical with RES_N in default configuration.
 43→//
 44→//There is an exception case when user needs to calculate nds_cos_xx and
 45→//nds32_sin_xx by input degree instead of redian. In this case, COS_RES_N should be set to 3600 manually.
 46→//So both value between RES_N and COS_RES_N are different.
 47→#ifndef COS_RES_N
 48→#define COS_RES_N   RES_N
 49→#endif
