290→/**
291→ * nds_truncate_(source type)_to_(destination type);
292→ *      Truncates the source type values to destination type.
293→ */
294→
295→/**
296→ * @brief truncate_src_to_dst
297→ * @param[in]   src input value.
298→ * @return output value after truncate.
299→ */
300→
301→// Q63 to Q(destination type)
302→static inline q31_t nds_truncate_q63_to_q31(q63_t src)
303→{
304→#ifdef NDS_CPU_64
305→    return src != (q31_t)src ?
306→           ((INT32_MAX ^ ((q31_t) (src >> 63)))) : (q31_t) src;
307→#else
308→    return ((q31_t) (src >> 32) != ((q31_t) src >> 31)) ?
309→           ((INT32_MAX ^ ((q31_t) (src >> 63)))) : (q31_t) src;
310→#endif
311→}
312→
313→#if 0
314→static inline q15_t nds_truncate_q63_to_q15(q63_t src)
315→{
316→    q31_t a = (src >> 32);
317→    q31_t b = (src >> 15);
318→
319→    return (a == b) ? ((q15_t) src) : ((a >= 0) ? INT16_MAX : INT16_MIN);
320→}
321→
322→static inline q7_t nds_truncate_q63_to_q7(q63_t src)
323→{
324→    q31_t a = (src >> 32);
