739→int32_t riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_get_buffer_size(const uint16_t in_tensor_dim_x,
740→                                                                          const uint16_t in_tensor_dim_y,
741→                                                                          const uint16_t in_tensor_ch,
742→                                                                          const uint16_t out_tensor_ch,
743→                                                                          const uint16_t pad_x,
744→                                                                          const uint16_t pad_y,
745→                                                                          const uint16_t stride_x,
746→                                                                          const uint16_t stride_y,
747→                                                                          const uint16_t out_tensor_dim_x,
748→                                                                          const uint16_t out_tensor_dim_y)
749→{
750→    (void) pad_x;
751→    (void) pad_y;
752→    (void) stride_x;
753→    (void) stride_y;
754→    (void) out_tensor_dim_x;
755→    (void) out_tensor_dim_y;
756→    int32_t buf_size = 0;
757→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING)
758→    uint32_t buf_A = 0, buf_B = 0, buf_C = 0;
759→    const long align_byte = 64;
760→    uint32_t tiling_size = 256;
761→#ifdef DCACHE_SIZE
762→    int i;
763→    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
764→    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / (6 * sizeof(int8_t)));
765→    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
766→    {
767→        if (tiling_size_arr[i] > max_tile_size_in_cache)
768→        {
769→            tiling_size = tiling_size_arr[i - 1];
770→            break;
771→        }
772→    }
773→#endif
774→    if ((stride_x == 1) && (stride_y == 1))
775→    {
776→        buf_C = in_tensor_dim_x * in_tensor_dim_y * out_tensor_ch * sizeof(int32_t); //temp buffer for q31 tiling accumulator
777→        buf_C += align_byte - 1;
778→    }
779→    else
780→    {
781→        buf_A = tiling_size * in_tensor_ch * sizeof(int8_t); //tiling version
782→        buf_A += align_byte - 1;
783→        buf_C = tiling_size * out_tensor_ch * sizeof(int32_t); //temp buffer for q31 tiling accumulator
784→        buf_C += align_byte - 1;
785→    }
786→    buf_B = out_tensor_ch * in_tensor_ch * sizeof(int8_t); //converted src2
787→    buf_B += align_byte - 1;
788→    buf_size = buf_A + buf_B + buf_C;
789→#else
790→    (void) in_tensor_dim_x;
791→    (void) in_tensor_dim_y;
792→    (void) in_tensor_ch;
793→    (void) out_tensor_ch;
794→#endif
795→    return buf_size;
796→}
