 690→
 691→    /* left-over part of the rows */
 692→
 693→    rowCnt = wt_row_num & 0x3;
 694→    while (rowCnt)
 695→    {
 696→        q63_t     sum_q31x2 = 0;
 697→        uint16_t  colCnt = size >> 3;
 698→
