 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→#if !defined(ENA_DSP_ISA) && !defined(ENA_VEC_ISA)
 24→#include "fixedpoint.h"
 25→#endif
 26→
 27→//// Activation Functions
 28→
 29→void riscv_nn_sigmoid_s8(const int32_t in_offset,
 30→                         const int16_t in_range_radius,
 31→                         const int16_t in_mult,
 32→                         const int16_t in_shift,
 33→                         const int32_t size,
 34→                         const int8_t* in_vec,
 35→                         int8_t* out_vec)
 36→{
 37→#ifdef ENA_EMPTY_FUN
 38→    //empty body
 39→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 40→    long vl;
 41→    long size2 = size;
 42→
 43→    const int32_t const_05 = 1 << 14;
 44→    const int32_t const_05n = (1 - (1 << 14)) + (1 << 15) - 1;              // div rounding need to add (1 << 15)
 45→    const int16_t const_127 = 127;
 46→    const int16_t const_128n = -128;
 47→
 48→    const long output_offset = -128;
 49→    if(in_shift >= 0)
 50→    {
 51→        const int32_t mul_pow2 = 1L << in_shift;
 52→        while(size2 > 0)
 53→        {
 54→            vl = __riscv_vsetvl_e8m2(size2);
 55→            vint8m2_t vIn_s8 = __riscv_vle8_v_i8m2(in_vec, vl);
 56→            vint16m4_t vIn_s16 = __riscv_vwadd_vx(vIn_s8, in_offset, vl);
 57→
 58→            vl = __riscv_vsetvl_e16m4(size2);
 59→            vint32m8_t vIn_s32 = __riscv_vwmul(vIn_s16, (long)in_mult, vl);
 60→
 61→            // SaturatingRoundingDoublingHighMul_with_Lsh
 62→            vl = __riscv_vsetvl_e32m8(size2);
 63→            vint32m8_t vOut_s32 = __riscv_vmul(vIn_s32, mul_pow2, vl);      // (ab_32*(1L << left_shift))
 64→            vbool4_t vMask = __riscv_vmslt(vIn_s32, 0, vl);                 // ab_32 < 0
 65→            vint32m8_t vVal1 = __riscv_vadd(vOut_s32, const_05, vl);
 66→            vint32m8_t vVal2 = __riscv_vadd(vOut_s32, const_05n, vl);
 67→            vOut_s32 = __riscv_vmerge_vvm_i32m8(vVal1, vVal2, vMask, vl);
 68→            vl = __riscv_vsetvl_e16m4(size2);
 69→            vint16m4_t vOut_s16 = __riscv_vnsra(vOut_s32, 15, vl);
 70→
 71→            vOut_s16 = nn_logistic_v(vOut_s16, vl);
 72→
 73→            long mask = (1<<7)-1;
 74→            vOut_s16 = nn_rounding_divide_by_pot16b_i16m4(vOut_s16, 7, mask, vl);
 75→
 76→            vl = __riscv_vsetvl_e8m2(size2);
 77→            vIn_s8 = __riscv_vle8_v_i8m2(in_vec, vl);
 78→            vIn_s16 = __riscv_vwadd_vx(vIn_s8, in_offset, vl);
 79→
 80→            vl = __riscv_vsetvl_e16m4(size2);
 81→            vOut_s16 = __riscv_vadd(vOut_s16, output_offset, vl);
 82→            vMask = __riscv_vmslt(vIn_s16, (long)-in_range_radius, vl);     // if input_val_centered < -in_range_radius
 83→            vOut_s16 = __riscv_vmerge_vxm_i16m4(vOut_s16, const_128n, vMask, vl);
 84→            vMask = __riscv_vmsgt(vIn_s16, (long)in_range_radius, vl);      // if input_val_centered > in_range_radius
 85→            vOut_s16 = __riscv_vmerge_vxm_i16m4(vOut_s16, const_127, vMask, vl);
 86→            vl = __riscv_vsetvl_e8m2(vl);
 87→            vint8m2_t vOut_s8 = __riscv_vnclip(vOut_s16, 0, __RISCV_VXRM_RNU, vl);
 88→            __riscv_vse8(out_vec, vOut_s8, vl);
 89→
 90→            out_vec += vl;
 91→            in_vec += vl;
 92→            size2 -= vl;
 93→        }
 94→    }
 95→    else // in_shift < 0
 96→    {
 97→        const int32_t shift_right = -in_shift;
 98→        while(size2 > 0)
 99→        {
100→            vl = __riscv_vsetvl_e8m2(size2);
101→            vint8m2_t vIn_s8 = __riscv_vle8_v_i8m2(in_vec, vl);
102→            vint16m4_t vIn_s16 = __riscv_vwadd_vx(vIn_s8, in_offset, vl);
103→
104→            vl = __riscv_vsetvl_e16m4(size2);
105→            vint32m8_t vIn_s32 = __riscv_vwmul(vIn_s16, (long)in_mult, vl);
106→
107→            // SaturatingRoundingDoublingHighMul_with_Lsh
108→            vl = __riscv_vsetvl_e32m8(size2);
109→            vint32m8_t vOut_s32 = __riscv_vsra(vIn_s32, shift_right, vl);   // (ab_32 >> (-left_shift))
110→            vbool4_t vMask = __riscv_vmslt(vIn_s32, 0, vl);                 // ab_32 < 0
111→            vint32m8_t vVal1 = __riscv_vadd(vOut_s32, const_05, vl);
112→            vint32m8_t vVal2 = __riscv_vadd(vOut_s32, const_05n, vl);
113→            vOut_s32 = __riscv_vmerge_vvm_i32m8(vVal1, vVal2, vMask, vl);
114→            vl = __riscv_vsetvl_e16m4(size2);
115→            vint16m4_t vOut_s16 = __riscv_vnsra(vOut_s32, 15, vl);
116→
117→            vOut_s16 = nn_logistic_v(vOut_s16, vl);
118→
119→            long mask = (1<<7)-1;
120→            vOut_s16 = nn_rounding_divide_by_pot16b_i16m4(vOut_s16, 7, mask, vl);
121→
122→            vl = __riscv_vsetvl_e8m2(size2);
123→            vIn_s8 = __riscv_vle8_v_i8m2(in_vec, vl);
124→            vIn_s16 = __riscv_vwadd_vx(vIn_s8, in_offset, vl);
125→
126→            vl = __riscv_vsetvl_e16m4(size2);
127→            vOut_s16 = __riscv_vadd(vOut_s16, output_offset, vl);
128→            vMask = __riscv_vmslt(vIn_s16, (long)-in_range_radius, vl);     // if input_val_centered < -in_range_radius
129→            vOut_s16 = __riscv_vmerge_vxm_i16m4(vOut_s16, const_128n, vMask, vl);
130→            vMask = __riscv_vmsgt(vIn_s16, (long)in_range_radius, vl);      // if input_val_centered > in_range_radius
131→            vOut_s16 = __riscv_vmerge_vxm_i16m4(vOut_s16, const_127, vMask, vl);
132→            vl = __riscv_vsetvl_e8m2(vl);
133→            vint8m2_t vOut_s8 = __riscv_vnclip(vOut_s16, 0, __RISCV_VXRM_RNU, vl);
134→            __riscv_vse8(out_vec, vOut_s8, vl);
135→
136→            out_vec += vl;
137→            in_vec += vl;
138→            size2 -= vl;
139→        }
140→    }
141→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
142→    long vl;
143→    long size2 = size;
144→
145→    const int32_t const_05 = 1 << 14;
146→    const int32_t const_05n = (1 - (1 << 14)) + (1 << 15) - 1; // div rounding need to add (1 << 15)
147→    const int16_t const_127 = 127;
148→    const int16_t const_128n = -128;
149→
150→    const long output_offset = -128;
151→    if(in_shift >= 0)
152→    {
153→        const int32_t mul_pow2 = 1L << in_shift;
154→        while(size2 > 0)
155→        {
156→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
157→            NDS_VEC_VLE8_V(NDS_VEC_V0, in_vec);
158→            NDS_VEC_VWADD_VX(NDS_VEC_V24, NDS_VEC_V0, in_offset);
159→
160→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
161→            NDS_VEC_VWMUL_VX(NDS_VEC_V16, NDS_VEC_V24, (long) in_mult);
162→
163→            // SaturatingRoundingDoublingHighMul_with_Lsh
164→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
165→            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V16, mul_pow2);     // (ab_32*(1L << left_shift))
166→            NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V16, 0);           // ab_32 < 0
167→            NDS_VEC_VADD_VX(NDS_VEC_V16, NDS_VEC_V8, const_05);
168→            NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V8, const_05n);
169→            NDS_VEC_VMERGE_VVM(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
170→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
171→            NDS_VEC_VNSRA_WI(NDS_VEC_V4, NDS_VEC_V16, 15);
172→
173→            logistic_v(vl);
174→
175→            long mask = (1<<7)-1;
176→            NN_RoundingDivideByPOT16b(NDS_VEC_V4, NDS_VEC_V4, 7, mask, NDS_VEC_V8, NDS_VEC_V12);
177→
178→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
179→            NDS_VEC_VLE8_V(NDS_VEC_V24, in_vec);
180→            NDS_VEC_VWADD_VX(NDS_VEC_V28, NDS_VEC_V24, in_offset);
181→
182→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
183→            NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, output_offset);
184→            NDS_VEC_VMSLT_VX(NDS_VEC_V0, NDS_VEC_V28, (long)-in_range_radius); // if input_val_centered < -in_range_radius
185→            NDS_VEC_VMERGE_VXM(NDS_VEC_V4, NDS_VEC_V4, const_128n);
186→            NDS_VEC_VMSGT_VX(NDS_VEC_V0, NDS_VEC_V28, (long)in_range_radius); // if input_val_centered > in_range_radius
187→            NDS_VEC_VMERGE_VXM(NDS_VEC_V4, NDS_VEC_V4, const_127);
188→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
189→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V4, 0);
190→            NDS_VEC_VSE8_V(NDS_VEC_V8, out_vec);
191→
192→            out_vec += vl;
193→            in_vec += vl;
194→            size2 -= vl;
195→        }
196→    }
197→    else // in_shift < 0
198→    {
199→        const int32_t shift_right = -in_shift;
200→        while(size2 > 0)
201→        {
202→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
203→            NDS_VEC_VLE8_V(NDS_VEC_V0, in_vec);
204→            NDS_VEC_VWADD_VX(NDS_VEC_V24, NDS_VEC_V0, in_offset);
205→
206→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
207→            NDS_VEC_VWMUL_VX(NDS_VEC_V16, NDS_VEC_V24, (long) in_mult);
208→
209→            // SaturatingRoundingDoublingHighMul_with_Lsh
210→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
211→            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V16, shift_right);      // (ab_32 >> (-left_shift))
212→            NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V16, 0);               // ab_32 < 0
213→            NDS_VEC_VADD_VX(NDS_VEC_V16, NDS_VEC_V8, const_05);
214→            NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V8, const_05n);
215→            NDS_VEC_VMERGE_VVM(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
216→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
217→            NDS_VEC_VNSRA_WI(NDS_VEC_V4, NDS_VEC_V16, 15);
218→
219→            logistic_v(vl);
220→
221→            long mask = (1<<7)-1;
222→            NN_RoundingDivideByPOT16b(NDS_VEC_V4, NDS_VEC_V4, 7, mask, NDS_VEC_V8, NDS_VEC_V12);
223→
224→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
225→            NDS_VEC_VLE8_V(NDS_VEC_V24, in_vec);
226→            NDS_VEC_VWADD_VX(NDS_VEC_V28, NDS_VEC_V24, in_offset);
227→
228→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
229→            NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, output_offset);
230→            NDS_VEC_VMSLT_VX(NDS_VEC_V0, NDS_VEC_V28, (long)-in_range_radius); // if input_val_centered < -in_range_radius
231→            NDS_VEC_VMERGE_VXM(NDS_VEC_V4, NDS_VEC_V4, const_128n);
232→            NDS_VEC_VMSGT_VX(NDS_VEC_V0, NDS_VEC_V28, (long)in_range_radius); // if input_val_centered > in_range_radius
233→            NDS_VEC_VMERGE_VXM(NDS_VEC_V4, NDS_VEC_V4, const_127);
234→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
235→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V4, 0);
236→            NDS_VEC_VSE8_V(NDS_VEC_V8, out_vec);
237→
238→            out_vec += vl;
239→            in_vec += vl;
240→            size2 -= vl;
241→        }
242→    }
243→#elif defined(ENA_DSP_ISA)
244→    int32_t c = 0;
245→    const int16_t output_offset = -128;
246→
247→    for (c = 0; c < size; ++c)
248→    {
249→        const int8_t input_val_s8 = in_vec[c];
250→        const int16_t input_val_centered = (int16_t)(input_val_s8) + in_offset;
251→
252→        int8_t output_val;
253→        if (input_val_centered < -in_range_radius)
254→        {
255→            output_val = -128;
256→        }
257→        else if (input_val_centered > in_range_radius)
258→        {
259→            output_val = 127;
260→        }
261→        else
262→        {
263→            //Rescale input (in_scale & fixedpointlization) to fixed point representation.
264→            const int16_t input_val_rescaled = SaturatingRoundingDoublingHighMul_with_Lsh(
265→                (int16_t)(input_val_centered),
266→                (int16_t)(in_mult), in_shift);
267→
268→            int16_t out_val_s16;
269→            logistic(input_val_rescaled, &out_val_s16);
270→
271→            //Rescale (inverse fixedpointization & requanitzation) to q7_t representation.
272→            int16_t output_val_s16 = RoundingDivideByPOT16b(out_val_s16, 7);
273→
274→            output_val_s16 += output_offset;
275→
276→            if (output_val_s16 == 128)
277→            {
278→                output_val_s16 = 127;
279→            }
280→            output_val = (int8_t)(output_val_s16);
281→        }
282→        out_vec[c] = output_val;
283→    }
284→#else
285→    int32_t c = 0;
286→    const int16_t output_offset = -128;
287→
288→    for (c = 0; c < size; ++c)
289→    {
290→        const int8_t input_val_s8 = in_vec[c];
291→        const int16_t input_val_centered = (int16_t)(input_val_s8) + in_offset;
292→
293→        int8_t output_val;
294→        if (input_val_centered < -in_range_radius)
295→        {
296→            output_val = -128;
297→        }
298→        else if (input_val_centered > in_range_radius)
299→        {
300→            output_val = 127;
301→        }
302→        else
303→        {
304→            //Rescale input (in_scale & fixedpointlization) to fixed point representation.
305→            const int16_t input_val_rescaled = SaturatingRoundingDoublingHighMul_with_Lsh(
306→                (int16_t)(input_val_centered),
307→                (int16_t)(in_mult), in_shift);
308→
309→            const struct FixedPoint input_val_f4 = FromRaw(input_val_rescaled, 4);//F4
310→            struct FixedPoint output_val_f0 = FromRaw(0, 0);
311→
312→            //kernel of sigmoid.
313→            logistic(input_val_f4, &output_val_f0);
314→
315→            //Rescale (inverse fixedpointization & requanitzation) to q7_t representation.
316→            int16_t output_val_s16 = RoundingDivideByPOT16b(output_val_f0.i_, 7);
317→
318→            output_val_s16 += output_offset;
319→
320→            if (output_val_s16 == 128)
321→            {
322→                output_val_s16 = 127;
323→            }
324→            output_val = (int8_t)(output_val_s16);
325→        }
326→        out_vec[c] = output_val;
327→    }
328→#endif
329→}
