 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→
 24→//// Activation Functions
 25→
 26→#ifdef ENA_VEC_ISA
 27→// following macro is for v-ext algorithm (if following macro is defined, vfdiv
 28→// will be replaced by vfrec7)
 29→// #define ENA_FAST_ALGO
 30→#endif
 31→
 32→#ifndef ENA_EMPTY_FUN
 33→//--- const values for tanh_f32 ---
 34→static const float32_t tanh_f32_max = TANH_F32_MAX;
 35→static const float32_t tanh_f32_min = TANH_F32_MIN;
 36→static const float32_t tanh_thr     = TANH_F32_THR;
 37→static const float32_t cst_1        = CST_1;
 38→static const float32_t cst_2        = CST_2;
 39→static const float32_t cst_1_3      = CST_1_3;
 40→
 41→
 42→
 43→#if !(defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU))
 44→extern float32_t exp_f32(float32_t x);
 45→extern float32_t tanh_f32(float32_t x)
 46→{
 47→    float32_t ret;
 48→    x = (x > tanh_f32_max)? tanh_f32_max : x;
 49→    x = (x < tanh_f32_min)? tanh_f32_min : x;
 50→
 51→    // x * (1 - x^2/3) if |x| < 5.e-3 or (exp2x - 1) / (exp2x + 1) otherwise
 52→    if(fabs(x) < tanh_thr)
 53→        ret = x * (1 - x*x*cst_1_3);
 54→    else
 55→        ret = (exp_f32(cst_2 * x) - cst_1) / (exp_f32(cst_2 * x) + cst_1);
 56→
 57→    return ret;
 58→}
 59→#endif
 60→#endif  //ENA_EMPTY_FUN
 61→
 62→int32_t riscv_nn_tanh_f32(const float32_t * in_vec, uint32_t size, float32_t * out_vec)
 63→{
 64→#ifdef ENA_EMPTY_FUN
 65→    //empty body
 66→#else
 67→#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && !defined(ENA_ACE_RVV)
 68→    //--- const values for taylor_poly_f32 ---
 69→    // Exponent polynomial coefficients
 70→    const float32_t exp_coe0 = EXP_COE0;
 71→    const float32_t exp_coe1 = EXP_COE1;
 72→    const float32_t exp_coe2 = EXP_COE2;
 73→    const float32_t exp_coe3 = EXP_COE3;
 74→    const float32_t exp_coe4 = EXP_COE4;
 75→    const float32_t exp_coe5 = EXP_COE5;
 76→    const float32_t exp_coe6 = EXP_COE6;
 77→    const float32_t exp_coe7 = EXP_COE7;
 78→
 79→    //--- const values for exp_f32 ---
 80→    const float32_t ln2         = LN2;          // ln(2)
 81→    const float32_t inv_ln2     = INV_LN2;      // 1/ln(2)
 82→#endif
 83→
 84→#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && defined(ENA_ACE_RVV)
 85→    long vl;
 86→    while(size > 0)
 87→    {
 88→        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 89→        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec);
 90→
 91→        //--- tanh_f32 begin ---
 92→        NDS_VEC_VFMAX_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_min);
 93→        NDS_VEC_VFMIN_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_max);
 94→
 95→        // tanh's results (for those fabs(x) < CONST_THR)
 96→        NDS_VEC_VMV_V_V(NDS_VEC_V8, NDS_VEC_V0);                    //copy of tanh input
 97→        NDS_VEC_VFMUL_VV(NDS_VEC_V16, NDS_VEC_V0, NDS_VEC_V0);      //x^2
 98→        NDS_VEC_VFMUL_VF(NDS_VEC_V24, NDS_VEC_V0, cst_1_3);         //x*cst_1_3
 99→        NDS_VEC_VFNMSAC_VV(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V24);   //x - x^3*cst_1_3
100→
101→        NDS_VEC_VFMUL_VF(NDS_VEC_V16, NDS_VEC_V0, cst_2);           //cst_2 * x
102→
103→        //--- exp_f32 begin ---
104→        ace_exp(NDS_VEC_V16, NDS_VEC_V16);
105→        //--- exp_f32 end ---
106→
107→        //(exp2x - 1) / (exp2x + 1)
108→        NDS_VEC_VFSUB_VF(NDS_VEC_V24, NDS_VEC_V16, cst_1);
109→        NDS_VEC_VFADD_VF(NDS_VEC_V16, NDS_VEC_V16, cst_1);
110→#ifdef ENA_FAST_ALGO
111→        NDS_VEC_VFRECE7_V(NDS_VEC_V16, NDS_VEC_V16);
112→        NDS_VEC_VFMUL_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V16);
113→#else
114→        NDS_VEC_VFDIV_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V16);
115→#endif
116→
117→        NDS_VEC_VFSGNJX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);     //fabs(x)
118→        NDS_VEC_VMFGE_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_thr);         //select those fabs(x) >= tanh_thr
119→        NDS_VEC_VMERGE_VVM(NDS_VEC_V24, NDS_VEC_V8, NDS_VEC_V24);
120→        //--- tanh_f32 end ---
121→
122→        NDS_VEC_VSE32_V(NDS_VEC_V24, out_vec);
123→        size -= vl;
124→        in_vec += vl;
125→        out_vec += vl;
126→    }
127→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU)
128→#ifdef ENA_VEC_INTRINSIC
129→    long vl;
130→    long size2 = size;
131→    while(size2 > 0)
132→    {
133→        vl = __riscv_vsetvl_e32m4(size2);
134→        vfloat32m4_t vin_vec = __riscv_vle32_v_f32m4(in_vec, vl);
135→        vin_vec = __riscv_vfmax(vin_vec, tanh_f32_min, vl);
136→        vin_vec = __riscv_vfmin(vin_vec, tanh_f32_max, vl);
137→        vin_vec = __riscv_vfmul(vin_vec, cst_2, vl);                           //cst_2 * x
138→
139→        //--- exp_f32 begin ---
140→        // Perform range reduction [-log(2),log(2)]
141→        vfloat32m4_t vm = __riscv_vfmul(vin_vec, inv_ln2, vl);                 //x * inv_ln2;
142→        vint32m4_t vm_int = __riscv_vfcvt_rtz_x(vm, vl);                       //m (integer type)
143→        vm = __riscv_vfcvt_f(vm_int, vl);                                      //m (float type)
144→        vm = __riscv_vfnmsub(vm, ln2, vin_vec, vl);                            //val
145→
146→        //--- taylor_poly_f32 begin ---
147→        vfloat32m4_t vaccumulator_a = __riscv_vfmv_v_f_f32m4(exp_coe0, vl);                   //A = exp_coe0
148→        vaccumulator_a = __riscv_vfmacc(vaccumulator_a, exp_coe4, vm, vl);                    //A = exp_coe0 + x * exp_coe4
149→        vfloat32m4_t vaccumulator_b = __riscv_vfmv_v_f_f32m4(exp_coe2, vl);                   //B = exp_coe2
150→        vaccumulator_b = __riscv_vfmacc(vaccumulator_b, exp_coe6, vm, vl);                    //B = exp_coe2 + x * exp_coe6
151→        vfloat32m4_t vaccumulator_c = __riscv_vfmv_v_f_f32m4(exp_coe1, vl);                   //C = exp_coe1
152→        vaccumulator_c = __riscv_vfmacc(vaccumulator_c, exp_coe5, vm, vl);                    //C = exp_coe1 + x * exp_coe5
153→        vfloat32m4_t vaccumulator_d = __riscv_vfmv_v_f_f32m4(exp_coe3, vl);                   //D = exp_coe3
154→        vaccumulator_d = __riscv_vfmacc(vaccumulator_d, exp_coe7, vm, vl);                    //D = exp_coe3 + x * exp_coe7
155→        vfloat32m4_t vz_float_pow2 = __riscv_vfmul(vm, vm, vl);                               //x2
156→        vm_int = __riscv_vsll(vm_int, 23, vl);                                                //m2
157→        vfloat32m4_t vz_float_pow4 = __riscv_vfmul(vz_float_pow2, vz_float_pow2, vl);         //x4
158→        vaccumulator_a = __riscv_vfmacc(vaccumulator_a, vaccumulator_b, vz_float_pow2, vl);   //A + B * x2
159→        vaccumulator_c = __riscv_vfmacc(vaccumulator_c, vaccumulator_d, vz_float_pow2, vl);   //C + D * x2
160→        vaccumulator_a = __riscv_vfmacc(vaccumulator_a, vaccumulator_c, vz_float_pow4, vl);   //(A + B * x2) + (C + D * x2) * x4
161→        //--- taylor_poly_f32 end ---
162→
163→        // Reconstruct
164→        vint32m4_t vaccumulator_a_int = __riscv_vreinterpret_i32m4(vaccumulator_a);
165→        //--- exp_f32 end ---
166→
167→        //(exp2x - 1) / (exp2x + 1)
168→        vaccumulator_a_int = __riscv_vsadd(vaccumulator_a_int, vm_int, vl);
169→        vaccumulator_a = __riscv_vreinterpret_f32m4(vaccumulator_a_int);
170→	vfloat32m4_t vin_tanh_vec = __riscv_vmv_v_v_f32m4(vin_vec, vl);                       //copy of tanh input
171→        vaccumulator_b = __riscv_vfmul(vin_vec, vin_vec, vl);                                 //x^2
172→        vaccumulator_c = __riscv_vfmul(vin_vec, cst_1_3, vl);                                 //x*cst_1_3
173→        vin_tanh_vec = __riscv_vfnmsac(vin_tanh_vec, vaccumulator_b, vaccumulator_c, vl);     //x - x^3*cst_1_3
174→
175→        //(exp2x - 1) / (exp2x + 1)
176→        vfloat32m4_t vden = __riscv_vfadd(vaccumulator_a, cst_1, vl);
177→        vaccumulator_a = __riscv_vfsub(vaccumulator_a, cst_1, vl);
178→        #ifdef ENA_FAST_ALGO
179→            vden = __riscv_vfrec7(vden, vl);
180→            vaccumulator_a = __riscv_vfmul(vaccumulator_a, vden, vl);
181→        #else
182→            vaccumulator_a = __riscv_vfdiv(vaccumulator_a, vden, vl);
183→        #endif
184→        vin_vec = __riscv_vfsgnjx(vin_vec, vin_vec, vl);                                       //fabs(x)
185→        vbool8_t vtemp_mask = __riscv_vmfge(vin_vec, tanh_thr, vl);                            //select those fabs(x) >= tanh_thr
186→        vfloat32m4_t vresult_float = __riscv_vmerge_vvm_f32m4(vin_tanh_vec, vaccumulator_a, vtemp_mask, vl);
187→
188→        __riscv_vse32(out_vec, vresult_float, vl);
189→        size2 -= vl;
190→        in_vec += vl;
191→        out_vec += vl;
192→    }
193→#else
194→    long vl;
195→    while(size > 0)
196→    {
197→        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
198→        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec);
199→
200→        //--- tanh_f32 begin ---
201→        NDS_VEC_VFMAX_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_min);
202→        NDS_VEC_VFMIN_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_max);
203→
204→        NDS_VEC_VFMUL_VF(NDS_VEC_V4, NDS_VEC_V0, cst_2);            //cst_2 * x
205→
206→        //--- exp_f32 begin ---
207→        // Perform range reduction [-log(2),log(2)]
208→        NDS_VEC_VFMUL_VF(NDS_VEC_V8, NDS_VEC_V4, inv_ln2);          //x * inv_ln2;
209→        NDS_VEC_VFCVT_RTZ_X_F_V(NDS_VEC_V8, NDS_VEC_V8);            //m (integer type)
210→        NDS_VEC_VFCVT_F_X_V(NDS_VEC_V12, NDS_VEC_V8);               //m (float type)
211→        NDS_VEC_VFNMSUB_VF(NDS_VEC_V12, ln2, NDS_VEC_V4);           //val
212→
213→        //--- taylor_poly_exp_f32 begin ---
214→        NDS_VEC_VFMV_V_F(NDS_VEC_V16, exp_coe0);                    //A = exp_coe0
215→        NDS_VEC_VFMACC_VF(NDS_VEC_V16, exp_coe4, NDS_VEC_V12);      //A = exp_coe0 + x * exp_coe4
216→        NDS_VEC_VFMV_V_F(NDS_VEC_V20, exp_coe2);                    //B = exp_coe2
217→        NDS_VEC_VFMACC_VF(NDS_VEC_V20, exp_coe6, NDS_VEC_V12);      //B = exp_coe2 + x * exp_coe6
218→        NDS_VEC_VFMV_V_F(NDS_VEC_V24, exp_coe1);                    //C = exp_coe1
219→        NDS_VEC_VFMACC_VF(NDS_VEC_V24, exp_coe5, NDS_VEC_V12);      //C = exp_coe1 + x * exp_coe5
220→        NDS_VEC_VFMV_V_F(NDS_VEC_V28, exp_coe3);                    //D = exp_coe3
221→        NDS_VEC_VFMACC_VF(NDS_VEC_V28, exp_coe7, NDS_VEC_V12);      //D = exp_coe3 + x * exp_coe7
222→        NDS_VEC_VFMUL_VV(NDS_VEC_V12, NDS_VEC_V12, NDS_VEC_V12);    //x2
223→        NDS_VEC_VSLL_VX(NDS_VEC_V8, NDS_VEC_V8, 23);                //m2
224→        NDS_VEC_VFMACC_VV(NDS_VEC_V16, NDS_VEC_V20, NDS_VEC_V12);   //A + B * x2
225→        NDS_VEC_VFMACC_VV(NDS_VEC_V24, NDS_VEC_V28, NDS_VEC_V12);   //C + D * x2
226→        NDS_VEC_VFMUL_VV(NDS_VEC_V12, NDS_VEC_V12, NDS_VEC_V12);    //x4
227→        NDS_VEC_VFMACC_VV(NDS_VEC_V16, NDS_VEC_V24, NDS_VEC_V12);   //(A + B * x2) + (C + D * x2) * x4
228→        //--- taylor_poly_exp_f32 end ---
229→
230→        // Reconstruct
231→        NDS_VEC_VSADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V8);
232→        //--- exp_f32 end ---
233→
234→        // TODO: it's possible to remove vmv_v_v
235→        // tanh's results (for those fabs(x) < CONST_THR)
236→        NDS_VEC_VMV_V_V(NDS_VEC_V4, NDS_VEC_V0);                    //copy of tanh input
237→        NDS_VEC_VFMUL_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V0);       //x^2
238→        NDS_VEC_VFMUL_VF(NDS_VEC_V12, NDS_VEC_V0, cst_1_3);         //x*cst_1_3
239→        NDS_VEC_VFNMSAC_VV(NDS_VEC_V4, NDS_VEC_V8, NDS_VEC_V12);    //x - x^3*cst_1_3
240→
241→        //(exp2x - 1) / (exp2x + 1)
242→        NDS_VEC_VFSUB_VF(NDS_VEC_V8, NDS_VEC_V16, cst_1);
243→        NDS_VEC_VFADD_VF(NDS_VEC_V16, NDS_VEC_V16, cst_1);
244→#ifdef ENA_FAST_ALGO
245→        NDS_VEC_VFRECE7_V(NDS_VEC_V16, NDS_VEC_V16);
246→        NDS_VEC_VFMUL_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V16);
247→#else
248→        NDS_VEC_VFDIV_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V16);
249→#endif
250→
251→        NDS_VEC_VFSGNJX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);     //fabs(x)
252→        NDS_VEC_VMFGE_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_thr);         //select those fabs(x) >= tanh_thr
253→        NDS_VEC_VMERGE_VVM(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V8);
254→        //--- tanh_f32 end ---
255→
256→        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec);
257→        size -= vl;
258→        in_vec += vl;
259→        out_vec += vl;
260→    }
261→#endif
262→#else
263→    long i;
264→    for(i=0; i<size; i++)
265→    {
266→        out_vec[i] = tanh_f32(in_vec[i]);
267→    }
268→#endif
269→#endif  // ENA_EMPTY_FUN
270→    return 0;
271→}
