 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→
 24→//// Softmax Functions
 25→
 26→int32_t riscv_nn_softmax_f32(const float32_t * in_vec, uint32_t size, float32_t * out_vec)
 27→{
 28→#ifdef ENA_EMPTY_FUN
 29→    //empty body
 30→#else
 31→#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && !defined(ENA_ACE_RVV)
 32→    //--- const values for taylor_poly_f32 ---
 33→    // Exponent polynomial coefficients
 34→    const float32_t exp_coe0 = EXP_COE0;
 35→    const float32_t exp_coe1 = EXP_COE1;
 36→    const float32_t exp_coe2 = EXP_COE2;
 37→    const float32_t exp_coe3 = EXP_COE3;
 38→    const float32_t exp_coe4 = EXP_COE4;
 39→    const float32_t exp_coe5 = EXP_COE5;
 40→    const float32_t exp_coe6 = EXP_COE6;
 41→    const float32_t exp_coe7 = EXP_COE7;
 42→    //--- const values for exp_f32 ---
 43→    const float32_t ln2      = LN2;          // ln(2)
 44→    const float32_t inv_ln2  = INV_LN2;      // 1/ln(2)
 45→#endif
 46→
 47→#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && defined(ENA_ACE_RVV)
 48→    float32_t max, sum;
 49→    float32_t *in_vec2, *out_vec2;
 50→    long vl;
 51→    long size2 = size;
 52→    long ele_per_loop, ele_per_loop2;
 53→
 54→    //find the maximun
 55→    in_vec2 = (float32_t *)in_vec;
 56→    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 57→    NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
 58→    in_vec2 += vl;
 59→    size2 -= vl;
 60→    while(size2 > 0)
 61→    {
 62→        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 63→        NDS_VEC_VLE32_V(NDS_VEC_V8, in_vec2);
 64→        in_vec2 += vl;
 65→        size2 -= vl;
 66→        NDS_VEC_VFMAX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
 67→    }
 68→    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note teh avl here
 69→    NDS_VEC_VFREDMAX_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);
 70→    NDS_VEC_VFMV_F_S(max, NDS_VEC_V0);
 71→
 72→    //calculate the exp and sum
 73→    NDS_VEC_VSETVLI(ele_per_loop2, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 74→    ele_per_loop = ele_per_loop2 * 3;
 75→    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 76→    NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);   //init sum
 77→    in_vec2 = (float32_t *)in_vec;
 78→    out_vec2 = out_vec;
 79→    size2 = size;
 80→    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 81→    while(size2 >= ele_per_loop)
 82→    {
 83→        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
 84→        in_vec2 += vl;
 85→        NDS_VEC_VLE32_V(NDS_VEC_V8, in_vec2);
 86→        in_vec2 += vl;
 87→        NDS_VEC_VLE32_V(NDS_VEC_V16, in_vec2);
 88→        in_vec2 += vl;
 89→        NDS_VEC_VFSUB_VF(NDS_VEC_V0, NDS_VEC_V0, max);
 90→        size2 -= ele_per_loop;
