 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→
 24→//// Basic Operation Functions
 25→
 26→int32_t riscv_nn_ew_mul_s8_asym(const int8_t * in_vec1,
 27→                                const int8_t * in_vec2,
 28→                                const int32_t in_offset1,
 29→                                const int32_t in_offset2,
 30→                                int8_t * out_vec,
 31→                                const int32_t out_offset,
 32→                                const int32_t out_scale,
 33→                                const int32_t out_shift,
 34→                                const int32_t act_min,
 35→                                const int32_t act_max,
 36→                                const uint32_t size)
 37→{
 38→#ifdef ENA_EMPTY_FUN
 39→    //empty body
 40→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 41→    const long total_out_shift = 31 - out_shift - 1;
 42→    long avl = size;
 43→    long vl;
 44→
 45→    while(avl > 0)
 46→    {
 47→        vl = __riscv_vsetvl_e8m1(avl);
 48→        vint8m1_t vA1_i8 = __riscv_vle8_v_i8m1(in_vec1, vl);
 49→        vint8m1_t vB1_i8 = __riscv_vle8_v_i8m1(in_vec2, vl);
 50→        vl = __riscv_vsetvl_e32m4(avl);
 51→        vint32m4_t vInput1_i32 = __riscv_vsext_vf4(vA1_i8, vl);
 52→        vint32m4_t vInput2_i32 = __riscv_vsext_vf4(vB1_i8, vl);
 53→        vint32m4_t vInput1_sum = __riscv_vadd(vInput1_i32, in_offset1, vl);
 54→        vint32m4_t vInput2_sum = __riscv_vadd(vInput2_i32, in_offset2, vl);
 55→        vint32m4_t vProduct_i32 = __riscv_vmul(vInput1_sum, vInput2_sum, vl);
 56→
 57→        vint64m8_t vProduct_i64 = __riscv_vwmul(vProduct_i32, out_scale, vl);
 58→        vint32m4_t vProduct_nsra_i32 = __riscv_vnsra(vProduct_i64, total_out_shift, vl);
 59→        vint32m4_t vProduct_ssra_i32 = __riscv_vssra(vProduct_nsra_i32, 1, __RISCV_VXRM_RNU, vl);
 60→
 61→        vint32m4_t vSum = __riscv_vadd(vProduct_ssra_i32, out_offset, vl);
 62→        vSum = __riscv_vmax(vSum, act_min, vl);
 63→        vSum = __riscv_vmin(vSum, act_max, vl);
 64→
 65→        vl = __riscv_vsetvl_e16m2(vl);
 66→        vint16m2_t vSum_nsra_i16 = __riscv_vnsra(vSum, 0, vl);
 67→        vl = __riscv_vsetvl_e8m1(vl);
 68→        vint8m1_t vSum_nsra_i8 = __riscv_vnsra(vSum_nsra_i16, 0, vl);
 69→        __riscv_vse8(out_vec, vSum_nsra_i8, vl);
 70→        in_vec1 += vl;
 71→        in_vec2 += vl;
 72→        out_vec += vl;
 73→        avl -= vl;
 74→    }
 75→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ELEN64)
 76→    uint32_t loop = size;
 77→    const long total_out_shift = 31 - out_shift - 1;
 78→    long vl;
 79→
 80→    while(loop > 0)
 81→    {
 82→        NDS_VEC_VSETVLI(vl, loop, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
 83→        NDS_VEC_VLE8_V(NDS_VEC_V8, in_vec1);
 84→        NDS_VEC_VLE8_V(NDS_VEC_V12, in_vec2);
 85→        NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V8);
 86→        NDS_VEC_VSEXT_VF4(NDS_VEC_V4, NDS_VEC_V12);
 87→        NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset1);
 88→        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, in_offset2);
 89→        NDS_VEC_VMUL_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
 90→
 91→        NDS_VEC_VWMUL_VX(NDS_VEC_V8, NDS_VEC_V0, out_scale);
 92→        NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, total_out_shift);
 93→        NDS_VEC_VSSRA_VI(NDS_VEC_V0, NDS_VEC_V8, 1);
 94→
 95→        NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, out_offset);
 96→        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, act_min);
 97→        NDS_VEC_VMIN_VX(NDS_VEC_V0, NDS_VEC_V0, act_max);
 98→
 99→        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
100→        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
101→        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
102→        NDS_VEC_VNSRA_WI(NDS_VEC_V16, NDS_VEC_V0, 0);
103→        NDS_VEC_VSE8_V(NDS_VEC_V16, out_vec);
104→        in_vec1 += vl;
105→        in_vec2 += vl;
106→        out_vec += vl;
107→        loop -= vl;
108→    }
109→#elif defined(ENA_DSP_ISA_64)
110→    uint32_t loop;
111→    int32_t in1, in2, out;
112→
113→    if (out_shift >= 0)
114→    {
115→        long_t in1_31, in1_20, in2_31, in2_20;
116→        long_t offset1_dual, offset2_dual;
117→        long_t mul;
118→
119→        offset1_dual = NDS_DSP_PKBB16(in_offset1, in_offset1);
120→        offset2_dual = NDS_DSP_PKBB16(in_offset2, in_offset2);
121→
122→        loop = size >> 2;
123→        while (loop > 0)
124→        {
125→            long_t in1_s8x4 = *__SIMD32(in_vec1)++;
126→            long_t in2_s8x4 = *__SIMD32(in_vec2)++;
127→            in1_31 = NDS_DSP_SUNPKD831(in1_s8x4);
128→            in1_20 = NDS_DSP_SUNPKD820(in1_s8x4);
129→            in2_31 = NDS_DSP_SUNPKD831(in2_s8x4);
130→            in2_20 = NDS_DSP_SUNPKD820(in2_s8x4);
131→
132→            in1_31 = NDS_DSP_ADD16(in1_31, offset1_dual);
133→            in1_20 = NDS_DSP_ADD16(in1_20, offset1_dual);
134→
135→            in2_31 = NDS_DSP_ADD16(in2_31, offset2_dual);
136→            in2_20 = NDS_DSP_ADD16(in2_20, offset2_dual);
137→
138→            // unroll-1
139→            mul = NDS_DSP_SMUL16(in1_20, in2_20);
140→            out = nn_requantize(mul, out_scale, out_shift) + out_offset;
141→            out = nn_clip_any(out, act_min, act_max);
142→            *out_vec = out;
143→
144→            // unroll-3
145→            out = nn_requantize((mul>>32), out_scale, out_shift) + out_offset;
146→            out = nn_clip_any(out, act_min, act_max);
147→            *(out_vec+2) = out;
148→
149→            // unroll-2
150→            mul = NDS_DSP_SMUL16(in1_31, in2_31);
151→            out = nn_requantize(mul, out_scale, out_shift) + out_offset;
152→            out = nn_clip_any(out, act_min, act_max);
153→            *(out_vec+1) = out;
154→
155→            // unroll-4
156→            out = nn_requantize((mul>>32), out_scale, out_shift) + out_offset;
157→            out = nn_clip_any(out, act_min, act_max);
158→            *(out_vec+3) = out;
159→
160→            out_vec += 4;
161→            loop--;
162→        }
163→    }
164→    else
165→    {
166→        long_t in1_31 = 0, in1_20 = 0, in2_31 = 0, in2_20 = 0;
167→        long_t offset1_dual = NDS_DSP_PKBB16(in_offset1, in_offset1);
168→        long_t offset2_dual = NDS_DSP_PKBB16(in_offset2, in_offset2);
169→        uint32_t out_rshift = -out_shift;
170→        long_t out1_s32x2 = 0, out2_s32x2 = 0;
171→        long_t out_offset_s32x2 = NDS_DSP_PKBB32(out_offset, out_offset);
172→        long_t max_s32x2 = NDS_DSP_PKBB32(act_max, act_max);
173→        long_t min_s32x2 = NDS_DSP_PKBB32(act_min, act_min);
174→        long_t out_scale_s32x2  = NDS_DSP_PKBB32(out_scale, out_scale);
175→        loop = size >> 2;
176→        while (loop)
177→        {
178→            long_t in1_s8x4 = *__SIMD32(in_vec1)++;
179→            long_t in2_s8x4 = *__SIMD32(in_vec2)++;
180→            in1_31 = NDS_DSP_SUNPKD831(in1_s8x4);
181→            in1_20 = NDS_DSP_SUNPKD820(in1_s8x4);
182→            in2_31 = NDS_DSP_SUNPKD831(in2_s8x4);
183→            in2_20 = NDS_DSP_SUNPKD820(in2_s8x4);
184→            in1_31 = NDS_DSP_ADD16(in1_31, offset1_dual);
185→            in1_20 = NDS_DSP_ADD16(in1_20, offset1_dual);
186→            in2_31 = NDS_DSP_ADD16(in2_31, offset2_dual);
187→            in2_20 = NDS_DSP_ADD16(in2_20, offset2_dual);
188→            out1_s32x2 = NDS_DSP_SMUL16(in1_20, in2_20);
189→            out2_s32x2 = NDS_DSP_SMUL16(in1_31, in2_31);
190→            out1_s32x2 = NDS_DSP_KWMMUL(out1_s32x2, out_scale_s32x2);
191→            out2_s32x2 = NDS_DSP_KWMMUL(out2_s32x2, out_scale_s32x2);
192→            out1_s32x2 = NDS_DSP_SRA32_U(out1_s32x2, out_rshift);
193→            out2_s32x2 = NDS_DSP_SRA32_U(out2_s32x2, out_rshift);
194→            out1_s32x2 = NDS_DSP_ADD32(out1_s32x2, out_offset_s32x2);
195→            out2_s32x2 = NDS_DSP_ADD32(out2_s32x2, out_offset_s32x2);
196→            out1_s32x2 = NDS_DSP_SMAX32(out1_s32x2, min_s32x2);
197→            out2_s32x2 = NDS_DSP_SMAX32(out2_s32x2, min_s32x2);
198→            out1_s32x2 = NDS_DSP_SMIN32(out1_s32x2, max_s32x2);
199→            out2_s32x2 = NDS_DSP_SMIN32(out2_s32x2, max_s32x2);
200→            *out_vec++ = (int8_t)((out1_s32x2));
201→            *out_vec++ = (int8_t)((out2_s32x2));
202→            *out_vec++ = (int8_t)((out1_s32x2>>32));
203→            *out_vec++ = (int8_t)((out2_s32x2>>32));
204→            loop--;
205→        }
206→    }
207→
208→    loop = size & 0x3;
209→    while (loop > 0)
210→    {
211→        in1 = *in_vec1++ + in_offset1;
212→        in2 = *in_vec2++ + in_offset2;
213→
214→        out = in1 * in2;
215→        out = nn_requantize(out, out_scale, out_shift) + out_offset;
216→        out = nn_clip_any(out, act_min, act_max);
217→
218→        *out_vec++ = out;
219→        loop--;
220→    }
221→#elif defined(ENA_DSP_ISA)
222→    int32_t in1_31, in1_20, in2_31, in2_20;
223→    int32_t offset1_dual, offset2_dual;
224→    uint64_t mul;
225→    int32_t in1, in2, out;
226→
227→    offset1_dual = NDS_DSP_PKBB16(in_offset1, in_offset1);
228→    offset2_dual = NDS_DSP_PKBB16(in_offset2, in_offset2);
229→
230→    long loop = size >> 2;
231→    while (loop > 0)
232→    {
233→        in_vec1 = read_and_pad_reordered((int8_t *)in_vec1, &in1_20, &in1_31);
234→        in_vec2 = read_and_pad_reordered((int8_t *)in_vec2, &in2_20, &in2_31);
235→
236→        in1_31 = NDS_DSP_ADD16(in1_31, offset1_dual);
237→        in1_20 = NDS_DSP_ADD16(in1_20, offset1_dual);
238→
239→        in2_31 = NDS_DSP_ADD16(in2_31, offset2_dual);
240→        in2_20 = NDS_DSP_ADD16(in2_20, offset2_dual);
241→
242→        // unroll-1
243→        mul = NDS_DSP_SMUL16(in1_20, in2_20);
244→        out = nn_requantize(mul, out_scale, out_shift) + out_offset;
245→        out = nn_clip_any(out, act_min, act_max);
246→        *out_vec = out;
247→
248→        // unroll-3
249→        out = nn_requantize((mul>>32), out_scale, out_shift) + out_offset;
250→        out = nn_clip_any(out, act_min, act_max);
251→        *(out_vec+2) = out;
252→
253→        // unroll-2
254→        mul = NDS_DSP_SMUL16(in1_31, in2_31);
255→        out = nn_requantize(mul, out_scale, out_shift) + out_offset;
256→        out = nn_clip_any(out, act_min, act_max);
257→        *(out_vec+1) = out;
258→
259→        // unroll-4
260→        out = nn_requantize((mul>>32), out_scale, out_shift) + out_offset;
261→        out = nn_clip_any(out, act_min, act_max);
262→        *(out_vec+3) = out;
263→
264→        out_vec += 4;
265→        loop--;
266→    }
267→
268→    loop = size & 0x3;
269→    while (loop > 0)
270→    {
271→        in1 = *in_vec1++ + in_offset1;
272→        in2 = *in_vec2++ + in_offset2;
273→
274→        out = in1 * in2;
275→        out = nn_requantize(out, out_scale, out_shift) + out_offset;
276→        out = nn_clip_any(out, act_min, act_max);
277→
278→        *out_vec++ = out;
279→        loop--;
280→    }
281→#else
282→    long loop = size;
283→    int32_t in1, in2, out;
284→    while (loop > 0)
285→    {
286→        in1 = *in_vec1++ + in_offset1;
287→        in2 = *in_vec2++ + in_offset2;
288→
289→        out = in1 * in2;
290→        out = nn_requantize(out, out_scale, out_shift) + out_offset;
291→        out = nn_clip_any(out, act_min, act_max);
292→
293→        *out_vec++ = out;
294→        loop--;
295→    }
296→#endif
297→
298→  return 0;
299→}
