/** @file*/

#include "internal_nn_math.h"

//// Activation Functions

#ifdef ENA_VEC_ISA
// following macro is for v-ext algorithm (if following macro is defined, vfdiv
// will be replaced by vfrec7)
// #define ENA_FAST_ALGO
#endif

#ifndef ENA_EMPTY_FUN
//--- const values for tanh_f32 ---
static const float32_t tanh_f32_max = TANH_F32_MAX;
static const float32_t tanh_f32_min = TANH_F32_MIN;
static const float32_t tanh_thr     = TANH_F32_THR;
static const float32_t cst_1        = CST_1;
static const float32_t cst_2        = CST_2;
static const float32_t cst_1_3      = CST_1_3;



#if !(defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU))
extern float32_t exp_f32(float32_t x);
extern float32_t tanh_f32(float32_t x)
{
    float32_t ret;
    x = (x > tanh_f32_max)? tanh_f32_max : x;
    x = (x < tanh_f32_min)? tanh_f32_min : x;

    // x * (1 - x^2/3) if |x| < 5.e-3 or (exp2x - 1) / (exp2x + 1) otherwise
    if(fabs(x) < tanh_thr)
        ret = x * (1 - x*x*cst_1_3);
    else
        ret = (exp_f32(cst_2 * x) - cst_1) / (exp_f32(cst_2 * x) + cst_1);

    return ret;
}
#endif
#endif  //ENA_EMPTY_FUN

int32_t riscv_nn_tanh_f32(const float32_t * in_vec, uint32_t size, float32_t * out_vec)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#else
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && !defined(ENA_ACE_RVV)
    //--- const values for taylor_poly_f32 ---
    // Exponent polynomial coefficients
    const float32_t exp_coe0 = EXP_COE0;
    const float32_t exp_coe1 = EXP_COE1;
    const float32_t exp_coe2 = EXP_COE2;
    const float32_t exp_coe3 = EXP_COE3;
    const float32_t exp_coe4 = EXP_COE4;
    const float32_t exp_coe5 = EXP_COE5;
    const float32_t exp_coe6 = EXP_COE6;
    const float32_t exp_coe7 = EXP_COE7;

    //--- const values for exp_f32 ---
    const float32_t ln2         = LN2;          // ln(2)
    const float32_t inv_ln2     = INV_LN2;      // 1/ln(2)
#endif

#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && defined(ENA_ACE_RVV)
    long vl;
    while(size > 0)
    {
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec);

        //--- tanh_f32 begin ---
        NDS_VEC_VFMAX_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_min);
        NDS_VEC_VFMIN_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_max);

        // tanh's results (for those fabs(x) < CONST_THR)
        NDS_VEC_VMV_V_V(NDS_VEC_V8, NDS_VEC_V0);                    //copy of tanh input
        NDS_VEC_VFMUL_VV(NDS_VEC_V16, NDS_VEC_V0, NDS_VEC_V0);      //x^2
        NDS_VEC_VFMUL_VF(NDS_VEC_V24, NDS_VEC_V0, cst_1_3);         //x*cst_1_3
        NDS_VEC_VFNMSAC_VV(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V24);   //x - x^3*cst_1_3
